import{_ as l,o as s,c as i,a3 as e,az as n}from"./chunks/framework.BYuzD947.js";const g=JSON.parse('{"title":"第一节 机器语言到汇编语言","description":"","frontmatter":{},"headers":[],"relativePath":"Assembly/D1.第一节机器语言到汇编语言.md","filePath":"Assembly/D1.第一节机器语言到汇编语言.md"}'),t={name:"Assembly/D1.第一节机器语言到汇编语言.md"};function r(h,a,p,d,o,c){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="第一节-机器语言到汇编语言" tabindex="-1">第一节 机器语言到汇编语言 <a class="header-anchor" href="#第一节-机器语言到汇编语言" aria-label="Permalink to “第一节 机器语言到汇编语言”">​</a></h1><h2 id="一、机器语言的局限性" tabindex="-1">一、机器语言的局限性 <a class="header-anchor" href="#一、机器语言的局限性" aria-label="Permalink to “一、机器语言的局限性”">​</a></h2><h3 id="_1-1-机器语言的特点" tabindex="-1">1.1 机器语言的特点 <a class="header-anchor" href="#_1-1-机器语言的特点" aria-label="Permalink to “1.1 机器语言的特点”">​</a></h3><ul><li>由二进制代码（0和1）组成</li><li>计算机可以直接执行</li><li>执行效率最高</li></ul><h3 id="_1-2-机器语言的缺点" tabindex="-1">1.2 机器语言的缺点 <a class="header-anchor" href="#_1-2-机器语言的缺点" aria-label="Permalink to “1.2 机器语言的缺点”">​</a></h3><ul><li><strong>难以阅读和理解</strong>：全是0和1，没有语义</li><li><strong>难以调试</strong>：出错时很难定位问题</li><li><strong>可移植性差</strong>：不同CPU架构的机器语言完全不同</li><li><strong>容易出错</strong>：手动编写二进制代码容易出错</li></ul><h2 id="二、汇编语言的应用场景" tabindex="-1">二、汇编语言的应用场景 <a class="header-anchor" href="#二、汇编语言的应用场景" aria-label="Permalink to “二、汇编语言的应用场景”">​</a></h2><h3 id="_2-1-适用场景" tabindex="-1">2.1 适用场景 <a class="header-anchor" href="#_2-1-适用场景" aria-label="Permalink to “2.1 适用场景”">​</a></h3><ul><li>操作系统内核开发</li><li>嵌入式系统编程</li><li>性能要求极高的模块</li><li>设备驱动程序</li><li>逆向工程和漏洞分析</li></ul><h3 id="_10-2-不适用场景" tabindex="-1">10.2 不适用场景 <a class="header-anchor" href="#_10-2-不适用场景" aria-label="Permalink to “10.2 不适用场景”">​</a></h3><ul><li>大型应用程序开发</li><li>快速原型开发</li><li>跨平台软件开发</li></ul><h2 id="二、汇编语言的诞生" tabindex="-1">二、汇编语言的诞生 <a class="header-anchor" href="#二、汇编语言的诞生" aria-label="Permalink to “二、汇编语言的诞生”">​</a></h2><h3 id="_2-1-什么是汇编语言" tabindex="-1">2.1 什么是汇编语言 <a class="header-anchor" href="#_2-1-什么是汇编语言" aria-label="Permalink to “2.1 什么是汇编语言”">​</a></h3><p>汇编语言是机器语言的符号化表示，用助记符（Mnemonics）代替二进制操作码。</p><h3 id="_2-2-汇编语言的优势" tabindex="-1">2.2 汇编语言的优势 <a class="header-anchor" href="#_2-2-汇编语言的优势" aria-label="Permalink to “2.2 汇编语言的优势”">​</a></h3><ul><li><strong>可读性好</strong>：用英文单词或缩写表示指令</li><li><strong>易于编写</strong>：减少出错概率</li><li><strong>可调试性强</strong>：便于理解程序逻辑</li><li><strong>与机器语言一一对应</strong>：效率仍然很高</li></ul><h2 id="以16位为例说明-8086的总线宽度" tabindex="-1">以16位为例说明 8086的总线宽度 <a class="header-anchor" href="#以16位为例说明-8086的总线宽度" aria-label="Permalink to “以16位为例说明 8086的总线宽度”">​</a></h2><h3 id="总线" tabindex="-1">总线 <a class="header-anchor" href="#总线" aria-label="Permalink to “总线”">​</a></h3><ul><li>数据总线：用于传输数据</li><li>地址总线：用于传输地址</li><li>控制总线：用于传输控制信号</li></ul><h4 id="地址总线" tabindex="-1">地址总线 <a class="header-anchor" href="#地址总线" aria-label="Permalink to “地址总线”">​</a></h4><ul><li>地址总线为n时 对应寻址空间为2^n</li><li>用于指定存储单元的地址，决定了寻址空间的大小</li><li>例如，16位地址总线可以寻址2^16个存储单元（通常一个存储单元为1字节8bit）</li></ul><h4 id="数据总线" tabindex="-1">数据总线 <a class="header-anchor" href="#数据总线" aria-label="Permalink to “数据总线”">​</a></h4><ul><li>CPU与内存或其它器件之间的数据传送是通过数据总线来进行的。</li><li>数据总线的宽度决定了CPU和外界的数据传送速度。 数据总线宽度决定一次传送的数据量。一个通道为1位，一次即1bit数据。</li><li>例：向内存中写入数据89D8H时的数据传送</li><li>注意：1字节（1B） = 8位（8bit）</li></ul><h4 id="控制总线" tabindex="-1">控制总线 <a class="header-anchor" href="#控制总线" aria-label="Permalink to “控制总线”">​</a></h4><ul><li>控制总线 是一些不同控制信线的集合</li><li>cpu通过 控制总线 对外部设备进行控制</li><li>控制总线决定了CPU对外部设备的控制能力</li></ul><h4 id="数据如何表示" tabindex="-1">数据如何表示 <a class="header-anchor" href="#数据如何表示" aria-label="Permalink to “数据如何表示”">​</a></h4><ul><li>0100 1001 1101 1000B 二进制</li><li>44730O 八进制</li><li>49D8H 十六进制</li><li>18904D 十进制</li></ul><h2 id="三、机器语言与汇编语言的对应关系" tabindex="-1">三、机器语言与汇编语言的对应关系 <a class="header-anchor" href="#三、机器语言与汇编语言的对应关系" aria-label="Permalink to “三、机器语言与汇编语言的对应关系”">​</a></h2><h3 id="_3-1-操作码的映射" tabindex="-1">3.1 操作码的映射 <a class="header-anchor" href="#_3-1-操作码的映射" aria-label="Permalink to “3.1 操作码的映射”">​</a></h3><table tabindex="0"><thead><tr><th>机器语言（二进制）</th><th>汇编语言（助记符）</th><th>功能描述</th></tr></thead><tbody><tr><td>0000</td><td>NOP</td><td>空操作</td></tr><tr><td>0001</td><td>MOV</td><td>数据传送</td></tr><tr><td>0010</td><td>ADD</td><td>加法</td></tr><tr><td>0011</td><td>SUB</td><td>减法</td></tr><tr><td>0100</td><td>JMP</td><td>跳转</td></tr></tbody></table><h4 id="汇编语言" tabindex="-1">汇编语言 <a class="header-anchor" href="#汇编语言" aria-label="Permalink to “汇编语言”">​</a></h4><div class="language-assembly"><button title="Copy Code" class="copy"></button><span class="lang">assembly</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>MOV AX, 5    ; 向寄存器AX加载数据5</span></span>
<span class="line"><span>ADD AX, 3    ; AX寄存器加3</span></span>
<span class="line"><span>JMP 10       ; 跳转到地址10</span></span></code></pre></div><h2 id="四、汇编语言的基本组成" tabindex="-1">四、汇编语言的基本组成 <a class="header-anchor" href="#四、汇编语言的基本组成" aria-label="Permalink to “四、汇编语言的基本组成”">​</a></h2><h3 id="_4-1-指令-instructions" tabindex="-1">4.1 指令（Instructions） <a class="header-anchor" href="#_4-1-指令-instructions" aria-label="Permalink to “4.1 指令（Instructions）”">​</a></h3><ul><li>操作码（Opcode）：如 MOV、ADD、SUB</li><li>操作数（Operands）：寄存器 register、内存地址 [address]、立即数 immediate</li></ul><h3 id="_4-2-伪指令-directives" tabindex="-1">4.2 伪指令（Directives） <a class="header-anchor" href="#_4-2-伪指令-directives" aria-label="Permalink to “4.2 伪指令（Directives）”">​</a></h3><ul><li>指示汇编器如何处理程序</li><li>不生成机器码</li><li>示例：ORG、EQU、DB、DW</li></ul><h3 id="_4-3-标号-labels" tabindex="-1">4.3 标号（Labels） <a class="header-anchor" href="#_4-3-标号-labels" aria-label="Permalink to “4.3 标号（Labels）”">​</a></h3><ul><li>表示内存地址</li><li>便于程序跳转和数据访问</li><li>示例：START、LOOP、END</li></ul><h4 id="物理地址与段地址" tabindex="-1">物理地址与段地址 <a class="header-anchor" href="#物理地址与段地址" aria-label="Permalink to “物理地址与段地址”">​</a></h4><ul><li>在 8086 汇编中，“段地址 × 16 + 偏移地址 = 物理地址” CS:IP，其中 CS 是代码段寄存器，IP 是指令指针寄存器。</li><li>8086 其cpu是16位的，所以地址总线为16位，对应寻址空间为2^16个存储单元，其寄存器宽度为16位（16bit，2字节2B）。</li><li>CS和IP是不可直接访问的，只能通过指令来操作。在编程中不用考虑段地址，只需要考虑偏移地址。</li><li>编编程中，你几乎感觉不到 CS+IP 的存在，因为汇编器（编译器）帮你把这些脏活累活都干了。</li></ul><div class="language-assembly"><button title="Copy Code" class="copy"></button><span class="lang">assembly</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>    MOV AX, 1</span></span>
<span class="line"><span>    JMP label    ; 你只关心跳转到 label 这个标签,它计算出 label 标签距离当前指令的偏移地址，修改IP的值。</span></span>
<span class="line"><span>lab el:</span></span>
<span class="line"><span>    ADD AX, 2</span></span></code></pre></div><ul><li>在现代计算机中 是32位地址总线或者64位地址总线，对应寻址空间为2^32或2^64个存储单元。其寄存器宽度为32位或64位。</li><li></li></ul><h5 id="单位" tabindex="-1">单位 <a class="header-anchor" href="#单位" aria-label="Permalink to “单位”">​</a></h5><ul><li><strong>位（Bit）</strong>：最小的二进制单位，0或1</li><li><strong>字节（Byte）</strong>：8位，用于存储和处理数据的基本单位</li><li><strong>字（Word）</strong>：16位，用于存储和处理数据的基本单位（汇编里的 Word = 永远固定 16 位，2字节2B，16bit）</li><li><strong>机器字长（Machine Word Length）</strong>：指机器一次可以处理的最大数据长度，与计算机位数相同</li></ul><h2 id="五、汇编过程" tabindex="-1">五、汇编过程 <a class="header-anchor" href="#五、汇编过程" aria-label="Permalink to “五、汇编过程”">​</a></h2><h3 id="_5-1-汇编器的作用" tabindex="-1">5.1 汇编器的作用 <a class="header-anchor" href="#_5-1-汇编器的作用" aria-label="Permalink to “5.1 汇编器的作用”">​</a></h3><p>将汇编语言源程序翻译成机器语言目标程序。</p><h3 id="_5-2-汇编步骤" tabindex="-1">5.2 汇编步骤 <a class="header-anchor" href="#_5-2-汇编步骤" aria-label="Permalink to “5.2 汇编步骤”">​</a></h3><ol><li><strong>词法分析</strong>：识别助记符、标号、操作数</li><li><strong>语法分析</strong>：检查指令格式</li><li><strong>符号表建立</strong>：记录标号地址</li><li><strong>代码生成</strong>：将助记符转换为机器码</li><li><strong>链接</strong>：组合多个目标文件</li></ol><h2 id="七、寄存器的使用" tabindex="-1">七、寄存器的使用 <a class="header-anchor" href="#七、寄存器的使用" aria-label="Permalink to “七、寄存器的使用”">​</a></h2><h3 id="_7-1-通用寄存器-x86下的寄存器" tabindex="-1">7.1 通用寄存器 X86下的寄存器 <a class="header-anchor" href="#_7-1-通用寄存器-x86下的寄存器" aria-label="Permalink to “7.1 通用寄存器 X86下的寄存器”">​</a></h3><ul><li>AX、BX、CX、DX：通用数据寄存器 <ul><li>AX：累加器寄存器，用于累加和存储数据</li><li>BX：基址寄存器，用于存储基址</li><li>CX：计数寄存器，用于循环计数</li><li>DX：数据寄存器，用于存储数据</li></ul></li><li>SI、DI：源变址和目的变址寄存器（存放偏移地址）</li><li>SP、BP：栈指针和基址指针</li><li>CS、IP：代码段寄存器和指令指针寄存器</li></ul><h3 id="_7-2-段寄存器" tabindex="-1">7.2 段寄存器 <a class="header-anchor" href="#_7-2-段寄存器" aria-label="Permalink to “7.2 段寄存器”">​</a></h3><ul><li>CS：代码段寄存器</li><li>DS：数据段寄存器</li><li>ES：附加段寄存器</li><li>SS：栈段寄存器</li></ul><blockquote><p>在32位cpu CS、DS、SS 等段寄存器里存放的不再是直接的段基址，但依然是 16 位，而是一个叫“段选择子 (Selector)”的索引值（相当于一个数组下标） 64位cpu中，段寄存器被取消了,除了 FS 和 GS 这两个特殊的段寄存器外，其他的段寄存器（CS, DS, ES, SS）的段基址被 CPU 强制设为 0 彻底扁平化 线性地址 = 0 + 偏移地址,FS 和 GS 的特殊用途</p></blockquote><h2 id="六、常用汇编指令示例" tabindex="-1">六、常用汇编指令示例 <a class="header-anchor" href="#六、常用汇编指令示例" aria-label="Permalink to “六、常用汇编指令示例”">​</a></h2><h3 id="_6-1-数据传送指令" tabindex="-1">6.1 数据传送指令 <a class="header-anchor" href="#_6-1-数据传送指令" aria-label="Permalink to “6.1 数据传送指令”">​</a></h3><div class="language-assembly"><button title="Copy Code" class="copy"></button><span class="lang">assembly</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>MOV AX, BX      ; 将BX寄存器的值传送到AX</span></span>
<span class="line"><span>MOV [1000], AX  ; 将AX的值存入内存地址1000</span></span>
<span class="line"><span>MOV AX, [1000]  ; 从内存地址1000加载数据到AX</span></span></code></pre></div><h3 id="_6-2-算术运算指令" tabindex="-1">6.2 算术运算指令 <a class="header-anchor" href="#_6-2-算术运算指令" aria-label="Permalink to “6.2 算术运算指令”">​</a></h3><div class="language-assembly"><button title="Copy Code" class="copy"></button><span class="lang">assembly</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ADD AX, BX      ; AX = AX + BX</span></span>
<span class="line"><span>SUB AX, BX      ; AX = AX - BX</span></span>
<span class="line"><span>MUL AX, BX      ; AX = AX * BX</span></span>
<span class="line"><span>DIV AX, BX      ; AX = AX / BX</span></span>
<span class="line"><span>MOD AX, BX      ; AX = AX % BX</span></span>
<span class="line"><span>INC AX          ; AX加1</span></span>
<span class="line"><span>DEC AX          ; AX减1</span></span>
<span class="line"><span>CMP AX, BX      ; （就是减法方式）比较AX和BX的值 将结果存储在标志位中 （ZF、CF、SF、OF）</span></span></code></pre></div><h3 id="_6-3-逻辑运算指令" tabindex="-1">6.3 逻辑运算指令 <a class="header-anchor" href="#_6-3-逻辑运算指令" aria-label="Permalink to “6.3 逻辑运算指令”">​</a></h3><div class="language-assembly"><button title="Copy Code" class="copy"></button><span class="lang">assembly</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>AND AX, BX      ; 按位与</span></span>
<span class="line"><span>OR AX, BX       ; 按位或</span></span>
<span class="line"><span>XOR AX, BX      ; 按位异或</span></span>
<span class="line"><span>NOT AX          ; 按位取反</span></span></code></pre></div><h3 id="_6-4-控制转移指令" tabindex="-1">6.4 控制转移指令 <a class="header-anchor" href="#_6-4-控制转移指令" aria-label="Permalink to “6.4 控制转移指令”">​</a></h3><div class="language-assembly"><button title="Copy Code" class="copy"></button><span class="lang">assembly</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>JMP START       ; 无条件跳转到START</span></span>
<span class="line"><span>JZ LOOP         ; 结果为零时跳转</span></span>
<span class="line"><span>JC NEXT         ; 有进位时跳转</span></span>
<span class="line"><span>CALL SUBROUTINE ; 调用子程序</span></span>
<span class="line"><span>RET             ; 从子程序返回</span></span></code></pre></div><h2 id="九、汇编语言程序结构示例" tabindex="-1">九、汇编语言程序结构示例 <a class="header-anchor" href="#九、汇编语言程序结构示例" aria-label="Permalink to “九、汇编语言程序结构示例”">​</a></h2><div class="language-assembly"><button title="Copy Code" class="copy"></button><span class="lang">assembly</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>; 示例程序：计算1+2+3+...+10</span></span>
<span class="line"><span>ORG 100h        ; 程序起始地址</span></span>
<span class="line"><span></span></span>
<span class="line"><span>MOV CX, 10      ; 循环计数器</span></span>
<span class="line"><span>MOV AX, 0       ; 累加器</span></span>
<span class="line"><span></span></span>
<span class="line"><span>LOOP_START:</span></span>
<span class="line"><span>ADD AX, CX      ; 累加</span></span>
<span class="line"><span>DEC CX          ; 计数器减1</span></span>
<span class="line"><span>JNZ LOOP_START  ; 非零继续循环</span></span>
<span class="line"><span></span></span>
<span class="line"><span>MOV [RESULT], AX; 保存结果</span></span>
<span class="line"><span></span></span>
<span class="line"><span>HLT             ; 停机</span></span>
<span class="line"><span></span></span>
<span class="line"><span>RESULT DW 0     ; 结果存储位置</span></span>
<span class="line"><span>END</span></span></code></pre></div><h5 id="mov-指令" tabindex="-1">MOV 指令 <a class="header-anchor" href="#mov-指令" aria-label="Permalink to “MOV 指令”">​</a></h5><ul><li>mov target,source ; target表示目标寄存器或内存地址，source表示源寄存器或立即数</li><li>mov reg/mem,imm ; mem表示内存，imm表示立即数（数据）seg表示段寄存器 reg表示寄存器 <ul><li>示例：mov AX, 10H ; 将立即数0010H移动到AX寄存器 （立即数正数自动补0，负数高位全部补1，直到与target数的位数相同）</li><li>示例：mov DS, AX ; 将AX寄存器的值移动到DS数据段寄存器 mov [si], 1010H ; 将1010H的值移动到DS:[SI] 内存单元中 DS是数据段寄存器</li></ul></li><li>mov reg/mem/seg,reg</li><li>mov reg/seg,mem</li><li>mov reg/mem,seg</li></ul><blockquote><p>注意事项:</p><ol><li>target不能是CS（代码段寄存器）</li><li>target和source不能同时为内存数、段寄存器（CS\\DS\\ES\\SS\\FS\\GS）</li><li>target等于source的长度，才能将数据传送，立即数则是小于等于target的位数即可。</li><li>不能将立即数传送给段寄存器 5 target和source必须类型匹配，比如，要么都是字节，要么都是字或者都是双字等。</li><li>由于立即数没有明确的类型，所以将立即数传送到target时，系统会自动将立即数零扩展到与target数的位数相同，再进行传送。有时，需要用BYTE PTR、WORD PTR明确指出内存地址的位数</li></ol></blockquote><p><img src="`+n+'" alt="1780417007395"></p><ul><li>movzx target,source（不能是立即数） ; target必须大于source的长度 将source的值零扩展到与target数的位数相同，再传送。target必须是字节或字。 其他和mov指令相同。</li><li>movsx target,source（不能是立即数） ; target必须大于source的长度 将source的值高位全补1扩展到与target数的位数相同，再传送。target必须是字节或字。</li></ul><h5 id="jmp-指令" tabindex="-1">JMP 指令 <a class="header-anchor" href="#jmp-指令" aria-label="Permalink to “JMP 指令”">​</a></h5><ul><li>语法：JMP 目标地址</li><li>功能：无条件跳转到目标地址 修改的是 IP指令指针寄存器</li><li>示例：JMP label/address ; 跳转到标签label</li></ul><blockquote><p>需要注意的是，IP 寄存器的位宽会随着 CPU 工作模式的改变而扩展：</p><ul><li>在 16 位实模式下：它被称为 IP (Instruction Pointer)，是 16 位的。</li><li>在 32 位保护模式下：它被扩展为 EIP (Extended Instruction Pointer)，是 32 位的。</li><li>在 64 位长模式下：它被进一步扩展为 RIP (Extended Instruction Pointer)，是 64 位的。 无论名称和位宽如何变化，JMP 指令的本质操作始终是修改这个指向“下一条指令”的指针寄存器</li></ul></blockquote>',75)])])}const u=l(t,[["render",r]]);export{g as __pageData,u as default};
